 29→public fun ASTNode.nextLeaf(p: (ASTNode) -> Boolean): ASTNode? {
 30→    var n = this.nextLeafAny()
 31→    while (n != null && !p(n)) {
 32→        n = n.nextLeafAny()
 33→    }
 34→    return n
 35→}
