}", "new_string": "    private fun fixWhiteSpaceBetweenColonAndReturnType(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        require(node.elementType == COLON)
        node
            .nextLeaf()
            ?.takeIf { it.elementType == WHITE_SPACE }
            .let { whiteSpaceAfterColon ->
                if (whiteSpaceAfterColon?.text != " ") {
                    if (whiteSpaceAfterColon != null &&
                        whiteSpaceAfterColon.textContains('\n') &&
                        exceedsMaxLineLength(node)
                    ) {
                        // Merging the return type with the function signature would exceed the max line length. So do
                        // not report this as a lint violation. Note that the function-signature will take care of
                        // this kind of situations.
                        return
                    }
                    emit(node.startOffset, "Single space expected between colon and return type", true)
                    if (autoCorrect) {
                        node.upsertWhitespaceAfterMe(" ")
                    }
                }
            }
    }

    private fun exceedsMaxLineLength(colonNode: ASTNode): Boolean {
        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
            return false
        }

        // Calculate the length of the line if whitespace is replaced with a single space
        // This includes: text before colon on the same line + ":" + " " + return type text until end of line or newline
        val returnTypeText = getReturnTypeText(colonNode)
        // The column is 1-based and includes the colon itself
        // After the colon we'll have: " " + return type text
        val lineLength = colonNode.column + 1 + returnTypeText.length

        return lineLength > maxLineLength
    }

    private fun getReturnTypeText(colonNode: ASTNode): String {
        val returnTypeBuilder = StringBuilder()
        var currentNode = colonNode.nextLeaf()

        // Skip the whitespace after the colon
        if (currentNode?.elementType == WHITE_SPACE) {
            currentNode = currentNode.nextLeaf()
        }

        // Collect all text until we hit a newline (in whitespace) or reach the end
        while (currentNode != null) {
            if (currentNode.elementType == WHITE_SPACE && currentNode.textContains('\n')) {
                // Include text before the newline
                val text = currentNode.text
                val newlineIndex = text.indexOf('\n')
                returnTypeBuilder.append(text.substring(0, newlineIndex))
                break
            }
            returnTypeBuilder.append(currentNode.text)
            currentNode = currentNode.nextLeaf()
        }

        return returnTypeBuilder.toString()
    }
}"}

