import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionReturnTypeSpacingRuleMaxLineLengthTest {
    private val functionReturnTypeSpacingRuleAssertThat = assertThatRule { FunctionReturnTypeSpacingRule() }

    @Test
    fun `Given a function signature with return type on a new line and merging would exceed max line length then do not report`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function signature with return type on a new line and merging would not exceed max line length then report`() {
        val code =
            """
            fun foo():
                String {
            }
            """.trimIndent()
        val formattedCode =
            """
            fun foo(): String {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasLintViolation(1, 10, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a function signature with return type on a new line and max line length not set then report`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                AndAlsoALongReturnType {
            }
            """.trimIndent()
        val formattedCode =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction(): AndAlsoALongReturnType {
            }
            """.trimIndent()
        // When max line length is not set (off), the rule should still reformat
        functionReturnTypeSpacingRuleAssertThat(code)
            .hasLintViolation(1, 100, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a function signature with return type on a new line at exactly max line length when merged then do not report`() {
        // This function signature is exactly 120 characters when merged
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFun():
                SomeReturnType {
            }
            """.trimIndent()
        // "fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFun(): SomeReturnType {" = 100 chars
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 100)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with expression body and return type on a new line and merging would exceed max line length then do not report`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
                String = "result"
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasNoLintViolations()
    }
}
